mapper.select:
SELECT ip.TBL_INBOUND_PRODUCT_ID as tblInboundProductId, ip.CMPY_CD as cmpyCd, ip.AGNT_CD as agntCd, a.AGNT_NM as agntNm, ip.MTRL_CD as mtrlCd, ip.MTRL_NM as mtrlNm, ip.INBOUND_QUANTITY as inboundQuantity, ISNULL(ip.ACTUAL_QUANTITY, 0) as actualQuantity, ISNULL(ip.FAIL_QTY, 0) as failQty, (ip.INBOUND_QUANTITY - ISNULL(ip.ACTUAL_QUANTITY, 0) - ISNULL(ip.FAIL_QTY, 0)) as remainQuantity, ip.INBOUND_STATUS as inboundStatus, ip.EXPECTED_DATE as expectedDate, ISNULL(m.BARCODE,m.TBL_MTRL_M_ID) as barcode, (SELECT LOC_NM FROM TBL_WH_LOC_M WHERE LOC_CD = m.FIXED_LOC_CD) as fixedLocNm FROM TBL_INBOUND_PRODUCT ip LEFT JOIN TBL_AGENCY_M a ON ip.AGNT_CD = a.AGNT_CD AND ip.CMPY_CD = a.CMPY_CD LEFT JOIN TBL_MTRL_M m ON ip.MTRL_CD = m.MTRL_CD AND ip.AGNT_CD = m.AGNT_CD AND ip.CMPY_CD = m.CMPY_CD WHERE ip.CMPY_CD = #{cmpyCd}
AND ip.AGNT_CD = #{agntCd}
AND CONVERT(DATE, ip.EXPECTED_DATE) = CONVERT(DATE, #{expectedDate, jdbcType=VARCHAR}) AND (ip.DELETED_YN IS NULL OR ip.DELETED_YN = 'N') AND ip.INBOUND_STATUS != 'COMPLETED' AND (ip.INBOUND_QUANTITY - ISNULL(ip.ACTUAL_QUANTITY, 0) - ISNULL(ip.FAIL_QTY, 0)) > 0 ORDER BY ip.EXPECTED_DATE ASC, ip.SAVE_TIME ASC

SELECT ZONE_ID, ZONE_CD, ZONE_NM FROM TBL_WH_ZONE_M WHERE USE_YN = 'Y' AND DELETED_YN = 'N' AND WH_CD = '1000'
AND CMPY_CD = #{cmpyCd}
ORDER BY VIEW_SEQ

mapper.insert:
MERGE INTO dbo.TBL_STOCK AS target USING ( SELECT CAST(#{cmpyCd, jdbcType=VARCHAR} AS VARCHAR(10)) as cmpyCd, CAST(#{agntCd, jdbcType=VARCHAR} AS VARCHAR(20)) as agntCd, CAST(#{whCd, jdbcType=VARCHAR} AS VARCHAR(20)) as whCd, CAST(#{mtrlCd, jdbcType=VARCHAR} AS VARCHAR(100)) as mtrlCd, CAST(#{zoneId, jdbcType=BIGINT} AS BIGINT) as zoneId, CAST(#{locId, jdbcType=BIGINT} AS BIGINT) as locId, CAST(#{lotNo, jdbcType=VARCHAR} AS VARCHAR(50)) as lotNo ) AS source ON ( target.CMPY_CD = source.cmpyCd AND target.LOC_ID = source.locId AND target.MTRL_CD = source.mtrlCd AND ISNULL(target.LOT_NO, '') = ISNULL(source.lotNo, '') )
WHEN MATCHED THEN UPDATE SET STOCK_QTY = target.STOCK_QTY + #{putawayQty, jdbcType=INTEGER}, UPDT_TIME = GETDATE(), UPDT_USER = #{putawayUser, jdbcType=VARCHAR}
WHEN NOT MATCHED THEN INSERT ( CMPY_CD, AGNT_CD, WH_CD, MTRL_CD, ZONE_ID, LOC_ID, LOT_NO, EXPIRE_DATE, STOCK_QTY, UPDT_TIME, UPDT_USER ) VALUES ( source.cmpyCd, source.agntCd, source.whCd, source.mtrlCd, source.zoneId, source.locId, source.lotNo, #{expireDate, jdbcType=DATE}, #{putawayQty, jdbcType=INTEGER}, GETDATE(), #{putawayUser, jdbcType=VARCHAR} );

mapper.select:
SELECT
M.TBL_MTRL_M_ID as tblMtrlMId,
A.AGNT_NM as agntNm,
A.AGNT_CD as agntCd,
M.MTRL_NM as mtrlNm,
M.MTRL_CD as mtrlCd,
ISNULL(m.BARCODE,m.TBL_MTRL_M_ID) as barcode
FROM TBL_MTRL_M M
INNER JOIN TBL_AGENCY_M A ON M.AGNT_CD = A.AGNT_CD AND M.CMPY_CD = A.CMPY_CD
WHERE M.CMPY_CD = #{cmpyCd}
AND M.USE_YN = 'Y'
AND A.USE_YN = 'Y'

/* [수정 포인트] 키워드가 있을 때 명칭 혹은 바코드/코드 검색 */

    AND (
    /* 1. 상품명 AND 검색 (기존 로직 유지) */

        M.MTRL_NM LIKE '%' + #{word} + '%'


    /* 2. 또는 바코드/상품코드와 정확히 일치하는지 확인 (OR 조건 추가) */
    OR ISNULL(M.BARCODE,M.TBL_MTRL_M_ID) IN

        #{word}

    OR M.MTRL_CD IN

        #{word}

    )

ORDER BY M.MTRL_NM

mapper.update:
UPDATE TBL_INBOUND_PRODUCT
SET PUTAWAY_YN = CASE
                     WHEN ACTUAL_QUANTITY  <=  (
                         SELECT SUM(ISNULL(PUTAWAY_QTY, 0))
                         FROM TBL_WH_PUT_H
                         WHERE TBL_INBOUND_PRODUCT_ID = #{pId}
                           AND (DELETED_YN = 'N' OR DELETED_YN IS NULL)
                     ) THEN 'Y' ELSE 'N' END,
    UPDT_TIME = GETDATE()
WHERE TBL_INBOUND_PRODUCT_ID = #{pId}
  AND CMPY_CD = #{cmpyCd}
